def get_chat_id_for_session(session_id: str) -> int | None:
    """Возвращает chat_id владельца сессии или None, если сессия не привязана."""
    for chat_id, bound_session_id in _bindings.items():
        if bound_session_id == session_id:
            return chat_id
    return None
